import { signalStore, withState, withMethods, patchState, withComputed } from '@ngrx/signals';
import { rxMethod } from '@ngrx/signals/rxjs-interop';
import { inject } from '@angular/core';
import { NotesHttpService } from './services/notes-http.service';
import { pipe, switchMap, tap } from 'rxjs';
const initialState = {
  notes: [],
  loading: false,
  loaded: false
};
export const NotesStore = signalStore({
  providedIn: 'root'
}, withState(initialState), withComputed(store => ({
  importantNotes: () => store.notes().filter(note => note.important === true)
})), withMethods((store, notesHttpService = inject(NotesHttpService)) => ({
  loadAll: rxMethod(pipe(tap(() => patchState(store, {
    loading: true
  })), switchMap(() => notesHttpService.findAllNotes().pipe(tap({
    next: notes => {
      patchState(store, {
        notes,
        loading: false,
        loaded: true
      });
    },
    error: () => {
      patchState(store, {
        loading: false
      });
    }
  }))))),
  update: rxMethod(pipe(switchMap(({
    noteId,
    changes
  }) => notesHttpService.saveNote(noteId, changes).pipe(tap(() => {
    patchState(store, state => ({
      notes: state.notes.map(n => n.id === noteId ? {
        ...n,
        ...changes
      } : n)
    }));
  }))))),
  add: rxMethod(pipe(switchMap(note => notesHttpService.saveNote(note.id, note).pipe(tap(() => {
    patchState(store, state => ({
      notes: [...state.notes, note]
    }));
  })))))
})));
